ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT ?title WHERE {
  ?books a :Book .
  ?books p:Title ?title .
  ?books p:Book_Genre ?book_genre_w .
  ?books p:Book_Genre ?book_genre_w2 .
  ?books p:Year_Of_Publication ?year_of_publication_w .
  FILTER((((STR(?book_genre_w) = "Science Fiction Book" || STR(?book_genre_w2) = "Romance Book")) && (STR(?year_of_publication_w) = "2018" || STR(?year_of_publication_w) = "2018.0")))
} }
  low: { SELECT ?title WHERE {
  ?books a :Book .
  ?books p:Title ?title .
  ?books p:Book_Genre ?book_genre_w .
  ?books p:Book_Genre ?book_genre_w2 .
  ?books p:Year_Of_Publication ?year_of_publication_w .
  FILTER((STR(?book_genre_w) = "Science Fiction Book" || (STR(?book_genre_w2) = "Romance Book" && (STR(?year_of_publication_w) = "2018" || STR(?year_of_publication_w) = "2018.0"))))
} }
}
